import java.lang.Integer

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    val prefix = Array.ofDim[Long](n + 1)
    prefix(0) = 0L
    for (i <- 0 until n) {
        prefix(i + 1) = prefix(i) + nums(i)
    }

    val left_inc = Array.ofDim[Int](n)
    left_inc(0) = 0
    for (i <- 1 until n) {
        if (nums(i) > nums(i - 1)) {
            left_inc(i) = left_inc(i - 1)
        } else {
            left_inc(i) = i
        }
    }

    val right_inc = Array.ofDim[Int](n)
    right_inc(n - 1) = n - 1
    for (i <- (n - 2) to 0 by -1) {
        if (nums(i) < nums(i + 1)) {
            right_inc(i) = right_inc(i + 1)
        } else {
            right_inc(i) = i
        }
    }

    val right_dec = Array.ofDim[Int](n)
    right_dec(n - 1) = n - 1
    for (i <- (n - 2) to 0 by -1) {
        if (nums(i) > nums(i + 1)) {
            right_dec(i) = right_dec(i + 1)
        } else {
            right_dec(i) = i
        }
    }

    val A = Array.ofDim[Long](n)
    for (i <- 0 until n) {
        if (right_inc(i) >= i + 1) {
            A(i) = prefix(right_inc(i) + 1)
        } else {
            A(i) = Long.MinValue
        }
    }

    if (n == 0) {
        return 0L
    }

    val maxLog = (32 - Integer.numberOfLeadingZeros(n)) 
    val st = Array.ofDim[Long](maxLog, n)
    for (i <- 0 until n) {
        st(0)(i) = A(i)
    }

    for (j <- 1 until maxLog) {
        val step = 1 << (j - 1)
        val range = n - (1 << j)
        for (i <- 0 to range) {
            st(j)(i) = math.max(st(j - 1)(i), st(j - 1)(i + step))
        }
    }

    def rmq(l: Int, r: Int): Long = {
        if (l > r) {
            Long.MinValue
        } else {
            val len = r - l + 1
            val k = 31 - Integer.numberOfLeadingZeros(len)
            val segment1 = st(k)(l)
            val segment2 = st(k)(r - (1 << k) + 1)
            math.max(segment1, segment2)
        }
    }

    var ans = Long.MinValue
    for (p <- 0 until n) {
        if (left_inc(p) < p) {
            if (right_dec(p) >= p + 1) {
                val maxA = rmq(p + 1, right_dec(p))
                if (maxA != Long.MinValue) {
                    val cand = maxA - prefix(left_inc(p))
                    if (cand > ans) ans = cand
                }
            }
        }
    }
    ans
}
