class SegmentTree(n: Int, arr: Array[Long], comb: (Long, Long) => Long, identity: Long) {
    private val size = {
        var s = 1
        while (s < n) s = s << 1
        s
    }
    private val tree = Array.fill[Long](2 * size)(identity)

    for (i <- 0 until n) {
        tree(i + size) = arr(i)
    }
    for (i <- n until size) {
        tree(i + size) = identity
    }
    for (i <- size - 1 until 0 by -1) {
        tree(i) = comb(tree(2 * i), tree(2 * i + 1))
    }

    def query(l0: Int, r0: Int): Long = {
        var l = l0 + size
        var r = r0 + size
        var res = identity
        while (l <= r) {
            if ((l & 1) == 1) {
                res = comb(res, tree(l))
                l += 1
            }
            if ((r & 1) == 0) {
                res = comb(res, tree(r))
                r -= 1
            }
            l = l >> 1
            r = r >> 1
        }
        res
    }
}

