def solve(nums: Array[Long]): Long = {
    val n = nums.length
    val leftInc = Array.ofDim[Long](n)
    leftInc(0) = nums(0)
    for (i <- 1 until n) {
        if (nums(i) > nums(i-1)) {
            leftInc(i) = leftInc(i-1) + nums(i)
        } else {
            leftInc(i) = nums(i)
        }
    }

    val rightInc = Array.ofDim[Long](n)
    rightInc(n-1) = nums(n-1)
    for (i <- (n-2) to 0 by -1) {
        if (i < n-1 && nums(i) < nums(i+1)) {
            rightInc(i) = nums(i) + rightInc(i+1)
        } else {
            rightInc(i) = nums(i)
        }
    }

    val start = Array.ofDim[Int](n)
    val decSum = Array.ofDim[Long](n)
    start(0) = 0
    decSum(0) = nums(0)
    for (i <- 1 until n) {
        if (nums(i) < nums(i-1)) {
            start(i) = start(i-1)
            decSum(i) = decSum(i-1) + nums(i)
        } else {
            start(i) = i
            decSum(i) = nums(i)
        }
    }

    var ans = Long.MinValue
    for (i <- 1 until n-1) {
        val j = start(i)
        if (j < i) {
            if (nums(i) < nums(i+1)) {
                val cand1 = leftInc(j) - nums(j) + decSum(i)
                val total = cand1 + (rightInc(i) - nums(i))
                if (total > ans) ans = total
            }
        }
    }
    ans
}
```

### Explanation
1. **Precomputation**:
   - **Left Increasing Array (`leftInc`)**: This array is built by traversing left to right. For each element, if it is greater than the previous element, it extends the current increasing segment; otherwise, it starts a new segment.
   - **Right Increasing Array (`rightInc`)**: This array is built by traversing right to left. For each element, if it is less than the next element, it extends the current increasing segment; otherwise, it starts a new segment.
   - **Decreasing Segment Arrays (`start` and `decSum`)**: These arrays identify decreasing segments. For each element, if it is less than the previous element, it extends the current decreasing segment; otherwise, it starts a new segment.

2. **Combining Segments**:
   - For each potential valley index `i`, the solution checks if a valid decreasing segment ends at `i` (ensuring `start[i] < i`).
   - It then verifies that an increasing segment starts at `i` (ensuring `nums[i] < nums[i+1]`).
